#include <stdio.h>
#include <stdlib.h>

typedef enum { RED, BLACK } Color;

typedef struct Node {
    int key;
    struct Node *left, *right, *parent;
    Color color;
} Node;

typedef struct RedBlackTree {
    Node *root;
    Node *NIL;
} RedBlackTree;

Node* createNode(int key, Color color) {
    Node *node = (Node*)malloc(sizeof(Node));
    node->key = key;
    node->left = node->right = node->parent = NULL;
    node->color = color;
    return node;
}

RedBlackTree* createRBT() {
    RedBlackTree *rbt = (RedBlackTree*)malloc(sizeof(RedBlackTree));
    rbt->NIL = createNode(0, BLACK);
    rbt->root = rbt->NIL;
    return rbt;
}

void leftRotate(RedBlackTree *rbt, Node *x) {
    Node *y = x->right;
    x->right = y->left;
    if (y->left != rbt->NIL) y->left->parent = x;
    y->parent = x->parent;
    if (x->parent == NULL) rbt->root = y;
    else if (x == x->parent->left) x->parent->left = y;
    else x->parent->right = y;
    y->left = x;
    x->parent = y;
}

void rightRotate(RedBlackTree *rbt, Node *y) {
    Node *x = y->left;
    y->left = x->right;
    if (x->right != rbt->NIL) x->right->parent = y;
    x->parent = y->parent;
    if (y->parent == NULL) rbt->root = x;
    else if (y == y->parent->right) y->parent->right = x;
    else y->parent->left = x;
    x->right = y;
    y->parent = x;
}

void insertFixup(RedBlackTree *rbt, Node *z) {
    while (z->parent && z->parent->color == RED) {
        if (z->parent == z->parent->parent->left) {
            Node *y = z->parent->parent->right;
            if (y->color == RED) {
                z->parent->color = BLACK;
                y->color = BLACK;
                z->parent->parent->color = RED;
                z = z->parent->parent;
            } else {
                if (z == z->parent->right) {
                    z = z->parent;
                    leftRotate(rbt, z);
                }
                z->parent->color = BLACK;
                z->parent->parent->color = RED;
                rightRotate(rbt, z->parent->parent);
            }
        } else {
            Node *y = z->parent->parent->left;
            if (y->color == RED) {
                z->parent->color = BLACK;
                y->color = BLACK;
                z->parent->parent->color = RED;
                z = z->parent->parent;
            } else {
                if (z == z->parent->left) {
                    z = z->parent;
                    rightRotate(rbt, z);
                }
                z->parent->color = BLACK;
                z->parent->parent->color = RED;
                leftRotate(rbt, z->parent->parent);
            }
        }
        if (z == rbt->root) break;
    }
    rbt->root->color = BLACK;
}

void insert(RedBlackTree *rbt, int key) {
    Node *z = createNode(key, RED);
    Node *y = NULL;
    Node *x = rbt->root;
    while (x != rbt->NIL) {
        y = x;
        if (z->key < x->key) x = x->left;
        else x = x->right;
    }
    z->parent = y;
    if (y == NULL) rbt->root = z;
    else if (z->key < y->key) y->left = z;
    else y->right = z;
    z->left = rbt->NIL;
    z->right = rbt->NIL;
    insertFixup(rbt, z);
}

int search(RedBlackTree *rbt, int key) {
    Node *node = rbt->root;
    while (node != rbt->NIL && node->key != key) {
        if (key < node->key) node = node->left;
        else node = node->right;
    }
    return node != rbt->NIL;
}

void freeNode(Node *node, Node *NIL) {
    if (node == NIL) return;
    freeNode(node->left, NIL);
    freeNode(node->right, NIL);
    free(node);
}

void freeRBT(RedBlackTree *rbt) {
    freeNode(rbt->root, rbt->NIL);
    free(rbt->NIL);
    free(rbt);
}

int main() {
    RedBlackTree *rbt = createRBT();
    int keys[] = {10, 20, 30, 40};
    for (int i = 0; i < 4; i++) {
        insert(rbt, keys[i]);
    }
    printf("Search 30: %d\n", search(rbt, 30));
    printf("Search 50: %d\n", search(rbt, 50));
    freeRBT(rbt);
    return 0;
}
// Output: Search 30: 1
// Output: Search 50: 0

