        Node *node = root;
        while (node != NIL && node->key != key) {
            if (key < node->key) node = node->left;
            else node = node->right;
        }
        return node != NIL;
    }

    ~RedBlackTree() {
        deleteNode(root);
        delete NIL;
    }

    void deleteNode(Node *node) {
        if (node == NIL) return;
        deleteNode(node->left);
        deleteNode(node->right);
        delete node;
    }
};

