                        RightRotate(z);
                    }
                    z.Parent.Color = "BLACK";
                    z.Parent.Parent.Color = "RED";
                    LeftRotate(z.Parent.Parent);
                }
            }
            if (z == root) break;
        }
        root.Color = "BLACK";
    }

    public void Insert(int key) {
        Node z = new Node(key);
        Node y = null;
        Node x = root;
        while (x != NIL) {
