                        z = z->parent;
                        rightRotate(z);
                    }
                    z->parent->color = Color::BLACK;
                    z->parent->parent->color = Color::RED;
                    leftRotate(z->parent->parent);
                }
            }
            if (z == root) break;
        }
        root->color = Color::BLACK;
    }

public:
    RedBlackTree() {
